  <svg viewBox="0 0 700 260" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">Reforma cripto de Japón — qué cambia y cuándo entra en vigor</text>
    <g font-family="sans-serif">
      <rect x="15" y="48" width="200" height="70" rx="9" fill="#1c1c1f" stroke="#3f3f46" stroke-width="1.5"/>
      <text x="115" y="74" fill="#e4e4e7" text-anchor="middle" font-size="12" font-weight="700">Hoy: Ley de Serv. de Pago</text>
      <text x="115" y="94" fill="#71717a" text-anchor="middle" font-size="10">"medio de pago" · prot. consumidor</text>
      <text x="115" y="109" fill="#71717a" text-anchor="middle" font-size="10">sin herramientas de equidad</text>
