      <text x="370" y="74" fill="#a78bfa" text-anchor="middle" font-size="12" font-weight="700">Reforma: FIEA</text>
      <text x="370" y="94" fill="#e4e4e7" text-anchor="middle" font-size="10">"instrumento financiero" · integridad</text>
      <text x="370" y="109" fill="#e4e4e7" text-anchor="middle" font-size="10">supervisión SESC · veto al insider</text>
      <rect x="495" y="48" width="190" height="70" rx="9" fill="#0f2a1a" stroke="#22c55e" stroke-width="1.6"/>
